public class Main {
    static class Car {
        String brand; int year;
        Car(String b, int y) { brand = b; year = y; }
        void display() { System.out.println(brand + " (" + year + ")"); }
    }
    public static void main(String[] args) {
        Car c = new Car("Toyota", 2024);
        c.display();
