exercises.solutionCode:
public class Main {
    public static void main(String[] args) {
        try {
            Integer.parseInt("abc");
        } catch (NumberFormatException e) {
            System.out.println("Invalid number format!");
        }
        int num = Integer.parseInt("42");
        System.out.println(num);
    }
}
